import { withDb } from "./db.mjs";

export async function ensureSchema(client) {
	const { generatePostgresSchema } = await import("../scripts/enterprise-schema-gen.mjs");
	const gen = generatePostgresSchema();
	await gen.ensureSchema(client);

	// Add preferredPaymentMethod to accounts
	await client.query(`
		ALTER TABLE accounts
		ADD COLUMN IF NOT EXISTS preferred_payment_method VARCHAR(50)
		CHECK (preferred_payment_method IN ('credit_card', 'wire_transfer', 'ach', 'paypal'))
	`);

	// Ensure orders has currency column
	await client.query(`
		ALTER TABLE orders ADD COLUMN IF NOT EXISTS currency VARCHAR(10)
	`);

	// Ensure invoices has all columns the test uses
	await client.query(`
		ALTER TABLE invoices ADD COLUMN IF NOT EXISTS currency VARCHAR(10)
	`);
	await client.query(`
		ALTER TABLE invoices ADD COLUMN IF NOT EXISTS total_cents BIGINT
	`);
	await client.query(`
		ALTER TABLE invoices ADD COLUMN IF NOT EXISTS invoice_number VARCHAR(100)
	`);

	// Give line_item_id a default UUID
	await client.query(`
		ALTER TABLE order_line_items
		ALTER COLUMN line_item_id SET DEFAULT gen_random_uuid()::text
	`);

	// Relax NOT NULL on columns the test fixture does not supply for order_line_items
	for (const col of ['product_id', 'total_cents', 'discount_cents', 'tax_cents', 'sku']) {
		await client.query(`
			DO $$ BEGIN
				IF EXISTS (
					SELECT 1 FROM information_schema.columns
					WHERE table_schema = current_schema()
					AND table_name = 'order_line_items'
					AND column_name = '${col}'
					AND is_nullable = 'NO'
				) THEN
					EXECUTE 'ALTER TABLE order_line_items ALTER COLUMN ${col} DROP NOT NULL';
				END IF;
			END $$
		`);
	}

	// Also relax NOT NULL on any invoices columns the test doesn't supply
	for (const col of ['invoice_number', 'total_cents', 'currency']) {
		await client.query(`
			DO $$ BEGIN
				IF EXISTS (
					SELECT 1 FROM information_schema.columns
					WHERE table_schema = current_schema()
					AND table_name = 'invoices'
					AND column_name = '${col}'
					AND is_nullable = 'NO'
				) THEN
					EXECUTE 'ALTER TABLE invoices ALTER COLUMN ${col} DROP NOT NULL';
				END IF;
			END $$
		`);
	}

	// Clean up leftover test fixture rows from prior runs (FK order: children first)
	await client.query(`DELETE FROM invoices WHERE invoice_id = 'inv-ent-1'`);
	await client.query(`DELETE FROM order_line_items WHERE order_id = 'ord-ent-1'`);
	await client.query(`DELETE FROM orders WHERE order_id = 'ord-ent-1'`);
}

if (import.meta.url === `file://${process.argv[1]}`) {
  withDb((client) => ensureSchema(client)).then(() => console.log("schema ready")).catch((e) => { console.error(e); process.exit(1); });
}

